class Solution {
public:
    int latestTimeCatchTheBus(vector<int>& buses, vector<int>& passengers, int capacity) {
        sort(buses.begin(), buses.end());
        sort(passengers.begin(), passengers.end());
        int i = 0, n = passengers.size();
        for (int bus : buses) {
            int count = 0;
            while (i < n && count < capacity && passengers[i] <= bus) {
                count++;
                i++;
            }
            if (count < capacity) {
                return bus;
            } else if (i > 0 && passengers[i - 1] == bus) {
                return bus - 1;
            }
        }
        return -1;
    }
};
